changeSet.sql:
CREATE OR REPLACE FUNCTION auth_lookup_refresh_tenant(p_token_hash TEXT)
RETURNS UUID
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
STABLE
AS $body$
  SELECT tenant_id FROM refresh_sessions WHERE token_hash = p_token_hash LIMIT 1;
$body$;

REVOKE ALL ON FUNCTION auth_lookup_refresh_tenant(TEXT) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION auth_lookup_refresh_tenant(TEXT) TO auth_user;
